// tests/a7-configure/measurement-groups/media-assignment/media-assignment-access-guards.test.ts
//
// Verify users cannot interact with media configuration
// Users: Data Stream user / Data Stream admin / Publisher user / Publisher admin
//
// Expected:
// 1) "Configure" dropdown NOT available
// 2) Direct Media Assignment URL does not work (blocked)
//    (blocked = redirected away from MediaAssignment OR unauthorized/forbidden OR 401/403/404 OR "no access" text)

import { test, expect } from 'page-objects/myFixtures';
import type { Page } from '@playwright/test';
import { User, UserProvider } from '../../../../utils/UserProvider';
import { testParallel } from '../../../../env.config';

interface Scenario {
    user: User | undefined;
}

// ✅ Use the same real URL for all roles (as you asked)
const MEDIA_ASSIGNMENT_URL =
    'https://qa-beta.veevacrossix.com/Configure/MeasurementGroups/MediaAssignment/Abbott/FreeStyle%20Libre/FreeStyle%20Libre%202021';

const scenarios: Scenario[] = [
    {
        user: UserProvider.getUserByRole('dataStreamUser'),
    },
    {
        user: UserProvider.getUserByRole('dataStreamAdmin'),
    },    {
        user: UserProvider.getUserByRole('publisher'),
    },
    {
        user: UserProvider.getUserByRole('publisherAdmin'),
    },
];

async function expectConfigureHidden(page: Page) {
    const configureButton = page
        .getByRole('button', { name: /^configure$/i })
        .or(page.getByText(/^configure$/i));

    await expect(configureButton, `Configure should NOT be available`).toHaveCount(0);
}

async function assertBlockedOrReadOnly(page: Page, url: string, context: string) {
    const resp = await page.goto(url, { waitUntil: 'domcontentloaded' }).catch(() => null);
    const status = resp?.status?.() ?? null;

    await page.waitForTimeout(800);

    const finalUrl = page.url();

    const redirectedToLogin = /\/login/i.test(finalUrl) || /signin/i.test(finalUrl);
    const redirectedToForbidden = /unauthorized|forbidden|noaccess|accessdenied/i.test(finalUrl);
    const redirectedToHome = /\/home\//i.test(finalUrl);

    const noAccessText = page.locator(
        `text=/unauthorized|forbidden|don\\'t have access|no access|insufficient permissions/i`
    );

    const blocked =
        redirectedToLogin ||
        redirectedToForbidden ||
        redirectedToHome ||
        (status !== null && [401, 403, 404].includes(status)) ||
        (await noAccessText.isVisible().catch(() => false));

    if (blocked) return; // ✅ ok

    // Not blocked -> must be READ-ONLY (cannot interact)

    // Status dropdown is the most stable “interaction” probe
    const statusBtn = page.locator('button[data-hook="search-bar-status"]').first();

    // If status control doesn't exist -> read-only enough
    if ((await statusBtn.count().catch(() => 0)) === 0) return;

    // If disabled -> read-only
    const isDisabled = await statusBtn.isDisabled().catch(() => false);
    const className = (await statusBtn.getAttribute('class').catch(() => '')) || '';
    const visuallyDisabled =
        className.includes('currentValueDisabled') || className.toLowerCase().includes('disabled');

    if (isDisabled || visuallyDisabled) return; // ✅ ok

    // Try to open it. If it opens => interactive => FAIL
    await statusBtn.click({ timeout: 3000 }).catch(() => {});
    const popup = page.locator('div[role="listbox"], [role="menu"]').first();
    const popupVisible = await popup.isVisible().catch(() => false);

    expect(
        popupVisible,
        `Expected blocked OR read-only, but Status dropdown opened (interactive).
Context: ${context}
Final URL: ${finalUrl}
HTTP status: ${status}`
    ).toBeFalsy();
}


test.describe('RBAC – Restricted users cannot access Media Configuration', () => {
    test.describe.configure({ mode: testParallel });

    scenarios.forEach((scenario, index) => {
        const username = scenario.user?.username ?? 'UNKNOWN_USER';
        const role = scenario.user?.role ?? 'UNKNOWN_ROLE';
        const password = scenario.user?.password ?? 'UNKNOWN_PASSWORD';

        test(`Media Assignment access blocked (${role}) - ${index}`, {
            tag: ['@beta'],
            annotation: [
                { type: 'Severity', description: 'CRITICAL' },
                { type: 'Owner', description: 'Shachar Levy' },
                { type: 'Story', description: 'Measurement Groups: Media Assignment' },
                { type: 'Link', description: 'test 10 in - DNT-1052: https://crossixsolutions.atlassian.net/browse/DNT-1052' },
            ],
        }, async ({ loginPage, page }) => {

            // Login (same pattern as your successfulLogin test)
            await loginPage.navigateToLoginPage();
            await loginPage.login(username, password);
            await loginPage.expectLoginSuccess();

            // Expected #1: Configure hidden
            await expectConfigureHidden(page);

            // Expected #2: Direct URL blocked
            await assertBlockedOrReadOnly(page, MEDIA_ASSIGNMENT_URL, `${scenario.user} | MediaAssignment direct URL`);
        });
    });
});

// tests/a1-api/userProfile.test.ts
import { test, expect } from 'page-objects/myFixtures';
import { query, sql } from '../../utils/db/dbUtil';
import { User, UserProvider } from '../../utils/UserProvider';
import {callGetWithFileAndPageContext, callGetWithRequestFixture} from "@/utils/api/apiHelper";

interface LoginScenario {
    usr: User | undefined;
}

test.describe('User Profile API', () => {
  test.beforeEach(async ({}) => {
    test.info().annotations.push({ type: 'Story', description: 'User Profile' });
  });

  test('should successfully get the user profile for an authenticated user', {
    tag: ['@beta', '@gamma', '@prod', '@stage'],
  }, async ({ loggedInPage }) => {

    // Use the authenticatedApi fixture to make the GET request
    const response = await callGetWithRequestFixture(loggedInPage.page,'/api/v1/users/profile', 200,true);

    // Assert that the request was successful
    expect(response.status()).toBe(200);

    const body = await response.json();

    const user =  UserProvider.getUserByRole('admin');
    const expectedEmail = user?.email;
    const expectedFirstName = user?.firstName?.toLowerCase();
    const expectedLastName = user?.lastName?.toLowerCase();

    // Assert that the response body has the expected properties and values
    expect(body.email).toBe(expectedEmail);
    expect(body.firstName.toLocaleLowerCase()).toBe(expectedFirstName);
    expect(body.lastName.toLocaleLowerCase()).toBe(expectedLastName);
    // expect(body.defaultClientId).toBe(93);
    expect(body.displayRoleName).toBe('Crossix Admin');

    //Assert that the userRoles array contains the expected roles
    expect(body.userRoles).toEqual(expect.arrayContaining([
      'Editable Permissions',
      'Crossix User',
      'Access To Content Management',
      'Crossix Manager',
      'PubID Editing',
      'API',
      'Crossix Admin',
      'Dashboard View',
      'Dashboard Edit'
    ])
    );

    console.log('Successfully retrieved user profile data:', body);

    // Validate in DB that the user exists with the expected email
    const res = await query<{ id: number; firstName: string }>(
      'SELECT UserID AS id, FirstName AS firstName FROM dbo.[User] WHERE Email LIKE @email',
      [
        { name: 'email', type: sql.NVarChar, value: expectedEmail || '', length: 256 }
      ]
    );

    expect(res.recordset.length).toBeGreaterThan(0);
    expect(res.recordset[0].firstName.toLocaleLowerCase()).toBe(expectedFirstName);
  });

});
